import { notFound } from "next/navigation";import { respondToOpportunity } from "../actions";import { requireUser } from "@/src/lib/auth/session";import { createSupabaseServerClient } from "@/src/lib/supabase/server";
export default async function OpportunityDetail({params}:{params:Promise<{id:string}>}){const user=await requireUser();const vendor=user.memberships.find(m=>m.organizationType==="vendor");if(!vendor)notFound();const {id}=await params;const db=await createSupabaseServerClient();const [{data:request},{data:history}]=await Promise.all([db.from("property_manager_service_requests").select("*,properties(name,address_line_1,cities(name,state_code)),vendor_categories(name)").eq("id",id).eq("assigned_vendor_organization_id",vendor.organizationId).maybeSingle(),db.from("property_manager_service_request_history").select("status,note,created_at,vendor_visible").eq("request_id",id).eq("vendor_visible",true).order("created_at")]);if(!request)notFound();const accepted=request.accepted_vendor_organization_id===vendor.organizationId;const property=request.properties as unknown as {name:string;address_line_1:string;cities:{name:string;state_code:string}|null}|null;return <div><p className="text-sm font-semibold text-emerald-700">Vendor opportunity</p><h1 className="mt-1 text-4xl font-semibold">{(request.vendor_categories as unknown as {name:string}|null)?.name}</h1><p className="mt-3 text-sm text-slate-500">{property?.cities?`${property.cities.name}, ${property.cities.state_code}`:"Service area"} · {request.priority.replaceAll("_"," ")} · {request.status}</p><section className="mt-8 grid gap-6 lg:grid-cols-[1fr_.7fr]"><div className="rounded-2xl border border-slate-200 bg-white p-6"><h2 className="font-bold">Request details</h2><p className="mt-4 whitespace-pre-wrap text-sm leading-7 text-slate-600">{request.problem_description}</p>{accepted?<div className="mt-6 rounded-xl bg-emerald-50 p-4 text-sm"><p className="font-bold">Authorized property details</p><p className="mt-2">{property?.name}<br/>{property?.address_line_1}<br/>{request.address}{request.unit?` · Unit ${request.unit}`:""}<br/>{request.preferred_contact==="phone"?request.contact_phone:request.contact_email}</p></div>:<p className="mt-6 rounded-xl bg-slate-50 p-4 text-sm text-slate-500">Exact property and contact details become available after you accept this opportunity.</p>}<h2 className="mt-7 font-bold">Request timeline</h2><div className="mt-3 space-y-2">{(history??[]).map((item,i)=><p key={i} className="rounded-lg bg-slate-50 p-3 text-sm">{item.status} · {item.note??"Update"} · {new Date(item.created_at).toLocaleString()}</p>)}</div></div><aside className="rounded-2xl border border-slate-200 bg-white p-6"><h2 className="font-bold">Respond</h2>{!accepted?<><form action={respondToOpportunity} className="mt-4"><input type="hidden" name="id" value={id}/><input type="hidden" name="action" value="accept"/><button className="min-h-11 w-full rounded-xl bg-emerald-700 text-sm font-bold text-white">Accept opportunity</button></form><form action={respondToOpportunity} className="mt-3"><input type="hidden" name="id" value={id}/><input type="hidden" name="action" value="decline"/><textarea name="reason" maxLength={500} className="min-h-20 w-full rounded-xl border border-slate-200 p-3 text-sm" placeholder="Optional decline reason"/><button className="mt-2 min-h-11 w-full rounded-xl border border-rose-200 text-sm font-bold text-rose-700">Decline opportunity</button></form></>:<p className="mt-4 rounded-xl bg-emerald-50 p-4 text-sm font-semibold text-emerald-800">You accepted this opportunity.</p>}{request.photo_upload_requested?<p className="mt-5 text-xs text-slate-500">Photo upload was requested; file storage is not available yet.</p>:null}</aside></section></div>}
